var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 24일. 평행 세계 런던, <color=#ffd34c>미스캐토닉 대학</color>","JPN":"1888年10月24日｡パラレルワールドのロンドン、<color=#ffd34c>ミスカトニック大学</color>","ENG":"October 24, 1888, Parallel World London, <color=#ffd34c>Miskatonic University</color>","TWN":"1888年10月24日。平行世界倫敦，<color=#ffd34c>密斯卡托尼克大學</color>","SCN":"1888年10月24日。平行世界伦敦，<color=#ffd34c>密斯卡托尼克大学</color>","DEU":"October 24, 1888, Parallel World London, <color=#ffd34c>Miskatonic University</color>","FRA":"October 24, 1888, Parallel World London, <color=#ffd34c>Miskatonic University</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"……이상하군.","JPN":"……おかしいな。","ENG":"...Strange.","TWN":"好奇怪……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"급한 일이 아니라면, 그 모습으로 이곳에 찾아오지 말라고 했을 텐데?","JPN":"急用でないなら、その姿でここを訪ねて来るなと言ったはずだ。","ENG":"I told you not to show up here in that form unless it was urgent.","TWN":"我應該說過，如果沒有急事，不要以那種樣子來這裡吧？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"천사 강림 의식은 순조롭게 진행 중인가?","JPN":"天使降臨儀式は順調か？","ENG":"Is the angel descent ritual proceeding smoothly?","TWN":"天使降臨儀式進展順利嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"다음 희생양은 분명 <color=#ffd34c>금</color>이었지?","JPN":"次の犠牲者は確か<color=#ffd34c>金</color>だったか。","ENG":"The next sacrifice was supposed to be <color=#ffd34c>gold</color>, wasn't it?","TWN":"下一個犧牲品肯定是<color=#ffd34c>星期五</color>吧？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 필요한 제물은 <color=#ffd34c>심장</color>이겠군.","JPN":"ならば、必要な生贄は<color=#ffd34c>心臓</color>だな。","ENG":"Then the required offering must be a <color=#ffd34c>heart</color>.","TWN":"那麼所需的祭品就是<color=#ffd34c>心臟</color>了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"세계는 이미 임계치에 다다랐어. 자네는 이미 이 런던의 훌륭한 심볼이 되었지.","JPN":"世界はすでに臨界値に達した。君はもうこのロンドンの立派なシンボルになっている。","ENG":"The world has already reached its limit. You've become a fitting symbol of London.","TWN":"世界已經達到了臨界點。你已經成為了倫敦的一個偉大象徵。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 나의 최후의 걸작. 심야의 살인마여.","JPN":"マグヌム・オプス。私の最後の傑作。深夜の殺人鬼よ。","ENG":"The Magnum Opus. My final masterpiece. The Midnight Killer.","TWN":"偉大作品。我的最後傑作，午夜殺人魔。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"자네도 기억하고 있겠지? 그대가…….","JPN":"君も覚えているだろう？　汝の……","ENG":"You remember too, don't you...?","TWN":"你也記得吧？你……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"<color=#ffd34c>그대가 원하는 바를 해라. 그것이 곧 그대의 법이다.</color>","JPN":"<color=#ffd34c>汝の欲することを為せ、それが汝の法とならん。</color>","ENG":"<color=#ffd34c>Do what thou wilt. For it shall be thy law.</color>","TWN":"<color=#ffd34c>做你所願，這就是你的法則。</color>"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"물론, 잊고 싶어도 잊을 수 없겠죠.","JPN":"もちろん、忘れたくても忘れることはできないでしょう。","ENG":"Of course. I couldn't forget even if I wanted to.","TWN":"當然，即使想忘也忘不了吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"당신이 이 세계에서 저질렀던 그 거짓된 의식을.","JPN":"あなたがこの世界で犯したあの偽りの儀式を。","ENG":"That false ritual you carried out in this world.","TWN":"你在這個世界上犯下的那個虛假的儀式。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그리고 당신이 수많은 세계에서 수없이 반복해 왔던 어리석은 만행들을…….","JPN":"そして、あなたが多くの世界で、何度となく繰り返してきた愚かな蛮行を……","ENG":"And all the foolish atrocities you've repeated across countless worlds...","TWN":"還有你在無數個世界中無數次重複過的愚蠢暴行……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"하지만 이제 저는 알고 있답니다.","JPN":"ですが、私はもうわかっているのです。","ENG":"But now, I finally understand.","TWN":"但是現在我知道了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"당신이 무대에서 맡은 역할은 <color=#ffd34c>교황</color>…….","JPN":"あなたの舞台での役は<color=#ffd34c>教皇</color>……","ENG":"Your role on the stage is the <color=#ffd34c>Hierophant</color>...","TWN":"你在舞台上扮演的角色是<color=#ffd34c>教皇</color>……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"어느 세계에서든 높은 지위와 지식을 손에 넣지만, 어떤 세계에서도 그것에 만족하지 못하죠.","JPN":"どの世界でも高い地位と知識を手に入れますが、どの世界でもそれに満足できない。","ENG":"In every world, you attain status and knowledge, yet in none are you ever satisfied.","TWN":"無論在哪個世界，你都能獲得高位和知識，但在任何世界，都無法對此感到滿足。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그 탐욕의 끝에 금기를 범하고, 신적 존재에 다다르려 하는 것이 당신의 운명.","JPN":"その貪欲の果てに禁忌を犯し、神的存在にたどり着こうとするのがあなたの運命。","ENG":"At the end of your greed, you touch taboo, striving to become divine. That is your fate.","TWN":"在那貪婪的盡頭，觸犯禁忌，試圖達到神的境界是你的命運。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"하지만 모든 것은 각본대로…….","JPN":"ですが、すべては脚本どおりに……","ENG":"But everything according to the script...","TWN":"但一切都將按照劇本進行……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"걱정하지 마세요, 제임스 모리어티 교수.","JPN":"心配は不要です、ジェームス・モリアーティ教授。","ENG":"Don't worry, Professor James Moriarty.","TWN":"別擔心，詹姆斯·莫里蒂教授。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"당신은 여기서 퇴장하겠지만, 당신의 바람대로 곧 이 땅에 천사가 강림하게 될 테니까요.","JPN":"あなたはここで退場することになりますが、あなたの望みどおり、もうすぐこの地に天使が降臨するでしょうから。","ENG":"You may exit here, but just as you hoped, the angel will soon descend upon this land.","TWN":"你將會在這裡退場，但正如你所願，天使很快就會降臨到這片土地上。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"끝내 이 땅에 금빛 새벽을 맞이하게 만들 존재를 말이죠.","JPN":"この地に金色の暁を呼んでくる存在、がね。","ENG":"The one who will finally bring the golden dawn to this world.","TWN":"最終會讓這片土地迎來金色黎明的存在。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 25일. 평행 세계 런던, <color=#ffd34c>황금 새벽회</color> 지하 사원","JPN":"1888年10月25日。パラレルワールドのロンドン、<color=#ffd34c>黄金の暁団</color>地下寺院","ENG":"October 25, 1888, Parallel World London, <color=#ffd34c>Golden Dawn</color> Underground Temple","TWN":"1888年10月25日。平行世界倫敦，<color=#ffd34c>黃金黎明會</color>地下寺廟","SCN":"1888年10月25日。平行世界伦敦，<color=#ffd34c>黄金黎明会</color>地下寺庙","DEU":"October 25, 1888, Parallel World London, <color=#ffd34c>Golden Dawn</color> Underground Temple","FRA":"October 25, 1888, Parallel World London, <color=#ffd34c>Golden Dawn</color> Underground Temple"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"……경위님, 시간이 꽤 지났습니다.","JPN":"……警部補、時間がだいぶ過ぎております。","ENG":"...Lieutenant, it's been quite a while.","TWN":"……警衛，時間已經過了很久。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};